// Fetch verified common tokens from Supabase
const dbTokens = await $helpers.httpRequest({
  method: 'GET',
  url: 'https://ymwjfvtqtgtfqfiojsyx.supabase.co/rest/v1/common_tokens?select=symbol,mint',
  headers: {
    'apikey': 'sb_publishable_nI6zclBG_CYamJP5PjgXoA_dTzFBHWB',
    'Authorization': 'Bearer sb_publishable_nI6zclBG_CYamJP5PjgXoA_dTzFBHWB'
  }
});

// Build token map: symbol → mint
const tokenMap = {};
for (const token of dbTokens) {
  if (token.symbol && token.mint) tokenMap[token.symbol] = token.mint;
}

// Build live MEXC price map
const mexcPriceMap = {};
for (const item of $input.all()) {
  const t = item.json;
  if (typeof t.symbol === 'string' && t.symbol.endsWith('USDT')) {
    mexcPriceMap[t.symbol.slice(0, -4)] = parseFloat(t.price);
  }
}

// Intersect: tokens present on both exchanges right now
const result = [];
for (const [sym, mint] of Object.entries(tokenMap)) {
  if (mexcPriceMap[sym] !== undefined) {
    result.push({ symbol: sym, mint, mexcPrice: mexcPriceMap[sym] });
  }
}

return result.map(t => ({ json: t }));

const jupItems = $input.all();
const tokenItems = $('Find Common Tokens').all();
const spreads = [];
const timestamp = new Date().toISOString();

for (let i = 0; i < jupItems.length; i++) {
  const jupResp = jupItems[i].json;
  const token = tokenItems[i]?.json;
  if (!token) continue;

  // Ultra search returns array; pick first result matching our mint
  const results = Array.isArray(jupResp) ? jupResp : (jupResp.results || [jupResp]);
  const tokenData = results.find(r => r.address === token.mint || r.id === token.mint) || results[0];
  if (!tokenData) continue;

  const jupPrice = parseFloat(tokenData.price || tokenData.priceUsd || 0);
  const mexcPrice = token.mexcPrice;

  if (!jupPrice || isNaN(jupPrice) || isNaN(mexcPrice)) continue;

  const spreadPct = ((mexcPrice - jupPrice) / jupPrice) * 100;
  const absSpread = Math.abs(spreadPct);

  if (absSpread >= 5) {
    spreads.push({
      symbol: token.symbol,
      mint: token.mint,
      mexc_price: mexcPrice,
      jup_price: jupPrice,
      spread_pct: parseFloat(spreadPct.toFixed(4)),
      abs_spread_pct: parseFloat(absSpread.toFixed(4)),
      direction: spreadPct > 0 ? 'Buy JUP -> Sell MEXC' : 'Buy MEXC -> Sell JUP'
    });
  }
}

spreads.sort((a, b) => b.abs_spread_pct - a.abs_spread_pct);
return [{ json: { spreads, count: spreads.length, tokens_compared: jupItems.length, timestamp } }];
